mapper.select:
SELECT bl.id, p.display_name AS displayName, p.person_type::text AS personType, p.person_type::text AS personKind, p.employee_no AS employeeNo, bl.event_type AS eventType, bl.event_time AS eventTime, bl.snapshot_url AS snapshotUrl, bl.snapshot_url AS faceImageUrl, bl.video_url AS videoUrl, bl.location_id AS locationId, l.name AS locationName, bl.person_id AS personId, bl.track_key AS trackKey, bl.session_id AS sessionId, bl.face_match_score AS faceMatchScore, bl.body_match_score AS bodyMatchScore, bl.quality_flag AS qualityFlag, bl.behavior_analysis AS behaviorAnalysis, bl.created_at AS createdAt FROM behavior_logs bl LEFT JOIN locations l ON l.id = bl.location_id LEFT JOIN persons p ON p.id = bl.person_id
bl.event_time >= #{statDate}::date AND bl.event_time < (#{statDate}::date + INTERVAL '1 day')
AND bl.location_id = #{locationId}
AND bl.event_type = #{eventType}
ORDER BY bl.event_time DESC, bl.id DESC
LIMIT #{limit}

SELECT COUNT(1)
FROM behavior_logs
WHERE track_key = #{trackKey}
  AND event_type = #{eventType}
  AND event_time = #{eventTime}

mapper.update:
UPDATE behavior_logs
SET snapshot_url = #{snapshotUrl}
WHERE id = #{id}

UPDATE behavior_logs
SET behavior_analysis = #{behaviorAnalysis}
WHERE id = #{id}
